#include<bits/stdc++.h>
using namespace std;
long long a[10001],n,v[10001][10001][2];
long long dfs(long long l,long long r,long long sprt){
	if(l>=r) return a[l]*sprt;
    long long ans=0;
    if(v[l][r][0])  ans=max(a[l] * sprt + v[l][r][0],a[r] * sprt + v[l][r][1]);
	else ans=max(a[l] * sprt + (v[l][r][0]=dfs(l+1,r,sprt+1)),a[r] * sprt + (v[l][r][1]=dfs(l,r-1,sprt+1)));
     //cout<<l<<" "<<r<<":"<<sprt<<"::"<<ans<<"\n";
    return ans;
}
int main(){
	cin>>n;
	for(long long i=1;i<=n;i++) cin>>a[i];
	cout<<dfs(1,n,1);
}
